// Query Docker socket for labops container status
const { execSync } = require('child_process');

try {
  const raw = execSync(
    'docker ps -a --filter "name=labops-" --format "{{.Names}}|{{.Status}}|{{.State}}"',
    { encoding: 'utf-8', timeout: 10000 }
  );

  const containers = raw.trim().split('\n').filter(Boolean).map(line => {
    const [name, statusText, state] = line.split('|');
    let health = null;
    if (statusText.includes('healthy')) health = 'healthy';
    else if (statusText.includes('unhealthy')) health = 'unhealthy';
    else if (statusText.includes('starting')) health = 'starting';
    return { name, state, health, statusText };
  });

  return [{ json: { containers } }];
} catch(e) {
  return [{ json: { containers: [], error: e.message } }];
}

// Aggregate health check
const { execSync } = require('child_process');

const expected = [
  'labops-nginx', 'labops-n8n', 'labops-guacamole',
  'labops-guacd', 'labops-guac-postgres', 'labops-portainer'
];

let healthy = 0;
let total = expected.length;

try {
  const raw = execSync(
    'docker ps --filter "name=labops-" --format "{{.Names}}"',
    { encoding: 'utf-8', timeout: 5000 }
  );
  const running = raw.trim().split('\n').filter(Boolean);
  healthy = expected.filter(name => running.includes(name)).length;
} catch(e) {
  // Docker not available
}

const status = healthy === total ? 'healthy' : healthy > 0 ? 'degraded' : 'down';

return [{ json: { status, healthy, total, timestamp: new Date().toISOString() } }];

// Return dashboard configuration from environment variables
// This avoids hardcoding credentials in the HTML
return [{
  json: {
    guacProxy:     '/guacamole',
    guacAdmin:     process.env.GUAC_ADMIN_USER || 'guacadmin',
    guacAdminPw:   process.env.GUAC_ADMIN_PASSWORD || 'guacadmin',
    guacDs:        'postgresql',
    vmUser:        process.env.LAB_VM_USER || 'demo',
    vmPassword:    process.env.LAB_VM_PASSWORD || '',
    proxmoxUrl:    process.env.PROXMOX_URL || '',
  }
}];
